package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testToString() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        String result = csvFormat.toString();

        // Then
        assertEquals("Delimiter=<,> QuoteChar=<\"> RecordSeparator=<\r\n> EmptyLines:ignored SurroundingSpaces:ignored IgnoreHeaderCase:ignored SkipHeaderRecord:false HeaderComments:null Header:null", result);
    }
}
